package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

@Tag("timeout")
class ClonePair7753DifferenceFindingTest {

    private final ClonePair7753 subject = new ClonePair7753();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: no_termination.
     * Difference manifestation: the methods differ in whether they terminate.
     */
    @Test
    @BehavioralDifference(DifferenceType.NO_TERMINATION)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{-1, -10};
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1(((Integer) values[0]).intValue(), ((Integer) values[1]).intValue()), 200L, inputs);
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2(((Integer) values[0]).intValue(), ((Integer) values[1]).intValue()), 200L, inputs);

        assertCoreOutcome(
            method1Outcome,
            "TIMEOUT",
            null,
            null,
            "java.lang.Object[][Integer(-1),Integer(-10)]",
            "java.lang.Object[][Integer(-1),Integer(-10)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Integer(3)",
            null,
            "java.lang.Object[][Integer(-1),Integer(-10)]",
            "java.lang.Object[][Integer(-1),Integer(-10)]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
